import{_ as e,a as o,b as i,c as a,d as s}from"./chunks/sidebar-usage-limit.DcfHb4Cn.js";import{_ as n}from"./chunks/common-target-settings.BrkDtab5.js";import{_ as r}from"./chunks/sidebar-schedule-dates.AtfrOwJ1.js";import{_ as l,c,o as p,ag as u}from"./chunks/framework.DD2hp6gW.js";const d="/assets/selection-quantity-based.B3pazB8a.png",g="/assets/quantity-tier-single._U0b8DTn.png",h="/assets/quantity-tiers-multiple.B9G2NpDE.png",m="data:image/png;base64,",f="/assets/quantity-apply-discount-as.DgX9bzQY.png",y="/assets/quantity-next-discount-message-format.DCuVmae0.png",T="/assets/quantity-next-discount-message-location.Dwg0bjpC.png",N=JSON.parse('{"title":"Campaign Type: Quantity Based Discount","description":"","frontmatter":{},"headers":[],"relativePath":"campaigns/quantity-discounts.md","filePath":"campaigns/quantity-discounts.md","lastUpdated":1767081599000}'),b={name:"campaigns/quantity-discounts.md"};function q(S,t,x,v,A,C){return p(),c("div",null,t[0]||(t[0]=[u('<h1 id="campaign-type-quantity-based-discount" tabindex="-1">Campaign Type: Quantity Based Discount <a class="header-anchor" href="#campaign-type-quantity-based-discount" aria-label="Permalink to &quot;Campaign Type: Quantity Based Discount&quot;">​</a></h1><p>A <strong>Quantity Based Discount</strong> is a powerful tool for creating tiered pricing structures that reward customers for buying in bulk. This encourages larger order values by reducing the per-item cost as the quantity increases.</p><p>This is the perfect campaign type for scenarios like:</p><ul><li>&quot;Buy 3 or more, get 10% off each&quot;</li><li>&quot;Buy a case of 12 and get $2 off each bottle&quot;</li><li>Creating wholesale-style pricing for regular customers.</li></ul><p>This guide will walk you through every field required to set up this campaign type.</p><h2 id="step-1-select-your-campaign-type" tabindex="-1">Step 1: Select Your Campaign Type <a class="header-anchor" href="#step-1-select-your-campaign-type" aria-label="Permalink to &quot;Step 1: Select Your Campaign Type&quot;">​</a></h2><p>To begin, navigate to <strong>CampaignBay → Add Campaign</strong>.</p><p><img src="'+d+'" alt="Select Campaign Type"></p><ul><li><strong>Select Discount Type:</strong> Choose <strong><code>Quantity Based Discount</code></strong> from the list. This configures the campaign to apply tiered pricing based on the number of items purchased.</li></ul><p><img src="'+e+'" alt="Campaign Title"></p><ul><li><strong>Campaign Title:</strong> Give your campaign a clear and descriptive name (e.g., &quot;T-Shirt Bulk Discount&quot;).</li></ul><p><img src="'+o+'" alt="Save Actions"></p><ul><li><strong>Select Status:</strong><ul><li><strong>Active:</strong> The campaign will be live as soon as its start time is reached.</li><li><strong>Inactive:</strong> The campaign will be saved as a draft.</li></ul></li></ul><h2 id="step-2-set-the-discount-target" tabindex="-1">Step 2: Set the Discount Target <a class="header-anchor" href="#step-2-set-the-discount-target" aria-label="Permalink to &quot;Step 2: Set the Discount Target&quot;">​</a></h2><p>This crucial step defines which products in your store are eligible for the quantity discount.</p><p><img src="'+n+'" alt="Discount Target"></p><p>The <strong>DISCOUNT TARGET</strong> dropdown provides powerful options to control the scope of your campaign, such as applying it to the entire store, specific products, or categories.</p><div class="info custom-block"><p class="custom-block-title">Learn More About Targeting</p><p>The &quot;Discount Target&quot; setting is a powerful feature shared by all campaign types. We&#39;ve created a dedicated guide to explain all of its options and conditional fields in detail.</p><p><strong><a href="./../core-concepts/targeting.html">Read the Full Guide: Targeting →</a></strong></p></div><h2 id="step-3-define-quantity-tiers" tabindex="-1">Step 3: Define Quantity Tiers <a class="header-anchor" href="#step-3-define-quantity-tiers" aria-label="Permalink to &quot;Step 3: Define Quantity Tiers&quot;">​</a></h2><p>This is the core of the Quantity Based Discount. Here you will define the specific pricing levels for your promotion.</p><p><img src="'+g+'" alt="Define Quantity Tiers"></p><p>You can create one or more tiers. Each tier has the following fields:</p><ul><li><strong>Buy from:</strong> The minimum quantity of an item a customer must have in their cart to qualify for this tier&#39;s discount.</li><li><strong>to:</strong> The maximum quantity for this tier. <strong>Leave this blank</strong> for the final tier to mean &quot;and up&quot; (e.g., 11 or more).</li><li><strong>Items, Get:</strong> The numeric value of the discount.</li><li><strong>% / Fixed ($) (Mode):</strong> The type of discount to apply. <ul><li><strong>Percentage (%):</strong> A percentage discount calculated on the price of each item.</li><li><strong>Fixed ($):</strong> A fixed amount deducted from the price of <strong>each individual item</strong>.</li></ul></li></ul><p><img src="'+h+'" alt="Multiple Tiers"></p><ul><li><strong>+ Add another tier:</strong> Click this to add more pricing levels to your campaign.</li></ul><p><img src="'+m+'" alt="Add Tier Button"></p><h3 id="example-tier-setup" tabindex="-1">Example Tier Setup <a class="header-anchor" href="#example-tier-setup" aria-label="Permalink to &quot;Example Tier Setup&quot;">​</a></h3><p>Here is an example of a multi-level discount for a product:</p><ul><li><strong>Tier 1:</strong> Buy from <code>3</code> to <code>5</code> items, get <code>10</code> <code>%</code></li><li><strong>Tier 2:</strong> Buy from <code>6</code> to <code>10</code> items, get <code>15</code> <code>%</code></li><li><strong>Tier 3:</strong> Buy from <code>11</code> to ``items, get<code>20</code> <code>%</code></li></ul><h2 id="step-4-set-conditions-optional" tabindex="-1">Step 4: Set Conditions (Optional) <a class="header-anchor" href="#step-4-set-conditions-optional" aria-label="Permalink to &quot;Step 4: Set Conditions (Optional)&quot;">​</a></h2><p>You can add specific rules to restrict who can use this discount (e.g., specific User Roles).</p><p><img src="'+i+'" alt="Conditions Overview"></p><p><strong><a href="./../core-concepts/conditions.html">Read the Full Guide: How to Use Conditions →</a></strong></p><h2 id="step-5-set-other-configurations-optional" tabindex="-1">Step 5: Set Other Configurations (Optional) <a class="header-anchor" href="#step-5-set-other-configurations-optional" aria-label="Permalink to &quot;Step 5: Set Other Configurations (Optional)&quot;">​</a></h2><p>This section provides additional rules for your campaign.</p><p><img src="'+a+'" alt="Exclude Sale Item"></p><ul><li><strong>Exclude Sale Items:</strong> Check this box if you do not want this campaign&#39;s discount to apply to products that are already on sale in WooCommerce. This is useful for preventing &quot;double discounting.&quot;</li></ul><p><img src="'+s+'" alt="Enable Usage Limit"></p><ul><li><strong>Enable Usage Limit:</strong> Check this box to set a maximum number of times this campaign can be used across your entire store. Once the limit is reached, the campaign will automatically become inactive.</li></ul><h2 id="step-6-set-the-schedule-optional" tabindex="-1">Step 6: Set the Schedule (Optional) <a class="header-anchor" href="#step-6-set-the-schedule-optional" aria-label="Permalink to &quot;Step 6: Set the Schedule (Optional)&quot;">​</a></h2><p>For a Scheduled Discount, setting the duration is essential. This section controls when your campaign will automatically start and end.</p><p><img src="'+r+'" alt="Enable Schedule"></p><ul><li><strong>Start Time / End Time:</strong> Use the date and time pickers to set the exact moment for the campaign to activate and expire.</li></ul><div class="tip custom-block"><p class="custom-block-title">Timezone Information</p><p>All dates and times are based on the timezone you have configured in your main WordPress settings under <strong>Settings → General → Timezone</strong>. The system automatically handles all UTC conversions for you.</p></div><div class="info custom-block"><p class="custom-block-title">Learn More About Automation</p><p>The status of your campaign is closely tied to the scheduling system, which uses WordPress Cron to automate activation and expiration.</p><p><strong><a href="./../core-concepts/scheduling-and-automation.html">Read the Full Guide: Scheduling &amp; Automation →</a></strong></p></div><h2 id="step-7-display-configurations" tabindex="-1">Step 7: Display Configurations <a class="header-anchor" href="#step-7-display-configurations" aria-label="Permalink to &quot;Step 7: Display Configurations&quot;">​</a></h2><p>This section controls how the offer is communicated to the customer, both on the product page and in their cart.</p><p><img src="'+f+'" alt="Apply Discount As"></p><ul><li><p><strong>Apply Discount As:</strong> Choose how the discount is displayed in the cart.</p><ul><li><strong>Strike through in line total:</strong> Shows the original price crossed out with the new quantity price next to it.</li></ul></li><li><p><strong>Cart Page Discount Message Format:</strong> Enter a message to display on the cart page when the discount is applied.</p><ul><li><em>Example:</em> <code>Quantity discount applied: {discount_amount}</code></li></ul></li><li><p><strong>Cart Page Message Location:</strong> Choose where the cart message should appear (e.g., next to the line item name).</p></li></ul><p><img src="'+y+'" alt="Next Discount Message"></p><ul><li><strong>Next Discount Message Format:</strong> Enter a custom message to be displayed on the cart item if the customer is close to unlocking the next discount tier. You can use placeholders like <code>{remainging_quantity_for_next_offer}</code>, <code>{percentage_off}</code>, and <code>{amount_off}</code>.</li></ul><p><img src="'+T+'" alt="Next Discount Message Location"></p><ul><li><strong>Cart Page Next Discount Message Location:</strong> Choose where the &quot;next discount&quot; upsell message should appear on the cart page.</li></ul><h2 id="step-8-save-the-campaign" tabindex="-1">Step 8: Save the Campaign <a class="header-anchor" href="#step-8-save-the-campaign" aria-label="Permalink to &quot;Step 8: Save the Campaign&quot;">​</a></h2><p>Once you have configured all the options, click the <strong>Save Campaign</strong> button at the top right of the page. After saving, you will be redirected back to the &quot;All Campaigns&quot; list.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Next, learn how to create campaigns that reward your first customers.</p><ul><li><strong><a href="./early-bird-discounts.html">Creating an Early Bird Discount →</a></strong></li></ul>',58)]))}const D=l(b,[["render",q]]);export{N as __pageData,D as default};
